class Solution:
    def reverseWords(self, s):
        out = []
        for w in s.split(' '):
            chars = list(w)
            lo, hi = 0, len(chars) - 1
            while lo < hi:
                chars[lo], chars[hi] = chars[hi], chars[lo]
                lo += 1
                hi -= 1
            out.append(''.join(chars))
        return ' '.join(out)

